from flask import Flask, request, jsonify, Response
import jwt
import requests
import os

app = Flask(__name__)

BACKEND_URL = os.getenv("BACKEND_URL", "http://localhost:5001")
JWT_SECRET = os.getenv("JWT_SECRET", "dev-secret")
